string GetFullReportJson(const std::vector<ModuleResult>& results, const std::string& scanId, const std::string& targetId) { JsonBuilder jb; jb.BeginObject(); jb.AddString("scan_id", scanId); jb.AddString("target_id", targetId); jb.AddString("timestamp", GetIsoTimestamp()); jb.AddString("hwid", GetHwid()); jb.AddString("computer_name", GetComputerName()); jb.AddString("username", GetUserName()); jb.AddString("windows_version", GetWindowsVersion()); jb.AddBool("is_admin", IsAdmin()); jb.AddString("ip_address", GetIPAddress()); jb.AddString("scanner_version", "3X-Forensic-Scanner v2.0"); jb.BeginObject("system_info"); jb.AddString("cpu", ""); jb.AddString("gpu", ""); jb.AddString("ram", ""); jb.EndObject(); auto counts = GetSeverityCounts(results); jb.BeginObject("summary"); jb.AddInt("critical", counts[SEV_CRITICAL]); jb.AddInt("high", counts[SEV_HIGH]); jb.AddInt("medium", counts[SEV_MEDIUM]); jb.AddInt("low", counts[SEV_LOW]); jb.AddInt("info", counts[SEV_INFO]); jb.AddInt("total", counts[SEV_CRITICAL] + counts[SEV_HIGH] + counts[SEV_MEDIUM] + counts[SEV_LOW] + counts[SEV_INFO]); jb.EndObject(); jb.BeginArray("modules"); for (const auto& mr : results) jb.AddModuleResult(mr); jb.EndArray(); jb.EndObject(); return jb.GetString(); }
std::string GetSystemInfoJson() { JsonBuilder jb; jb.BeginObject(); jb.AddString("computer_name", GetComputerName()); jb.AddString("username", GetUserName()); jb.AddString("windows_version", GetWindowsVersion()); jb.AddBool("is_admin", IsAdmin()); jb.AddString("ip_address", GetIPAddress()); jb.AddString("hwid", GetHwid()); jb.AddString("timestamp", GetIsoTimestamp()); jb.EndObject(); return jb.GetString(); }
std::map<std::string, int> GetSeverityCounts(const std::vector<ModuleResult>& results) { std::map<std::string, int> counts; counts[SEV_CRITICAL] = 0; counts[SEV_HIGH] = 0; counts[SEV_MEDIUM] = 0; counts[SEV_LOW] = 0; counts[SEV_INFO] = 0; for (const auto& mr : results) { for (const auto& f : mr.findings) counts[f.severity]++; } return counts; }
